CREATE OR REPLACE FUNCTION public._message_audit(_action text, _msg_id uuid, _conversation_id uuid, _sender_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_other UUID;
  v_user_a UUID;
  v_user_b UUID;
BEGIN
  SELECT user_a, user_b INTO v_user_a, v_user_b
    FROM public.conversations WHERE id = _conversation_id;
  v_other := CASE WHEN _sender_id = v_user_a THEN v_user_b ELSE v_user_a END;

  INSERT INTO public.audit_logs (
    actor_id, action, category, severity,
    entity_type, entity_id, metadata
  ) VALUES (
    _sender_id, _action, 'system', 'info',
    'message', _msg_id::text,
    jsonb_build_object(
      'conversation_id', _conversation_id,
      'sender_id', _sender_id,
      'recipient_id', v_other
    )
  );
END
$function$

CREATE OR REPLACE FUNCTION public._notify_forum_thread_author_on_reply()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _thread RECORD;
  _author_name TEXT;
BEGIN
  SELECT t.id, t.title, t.author_id, t.course_id, t.forum_id
    INTO _thread
    FROM public.forum_threads t WHERE t.id = NEW.thread_id;

  -- No notificar al autor cuando él mismo responde
  IF _thread.author_id IS NULL OR _thread.author_id = NEW.author_id THEN
    RETURN NEW;
  END IF;

  SELECT full_name INTO _author_name FROM public.profiles WHERE id = NEW.author_id;

  INSERT INTO public.notifications (user_id, title, body, kind, link)
  VALUES (
    _thread.author_id,
    'Nueva respuesta en tu pregunta del foro',
    COALESCE(_author_name, 'Alguien') || ' respondió a "' || _thread.title || '".',
    'info',
    '/app/forum/' || _thread.course_id::text || '/' || _thread.forum_id::text || '/' || _thread.id::text
  );

  RETURN NEW;
END
$function$

CREATE OR REPLACE FUNCTION public._recompute_project_submission_grade(_submission_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_project_id UUID;
  v_max_score NUMERIC;
  v_total_points NUMERIC;
  v_earned NUMERIC;
  v_new_sub_grade NUMERIC;
  v_factor NUMERIC;
  v_new_final NUMERIC;
BEGIN
  -- Resolver el project_id y max_score del proyecto.
  SELECT ps.project_id, p.max_score
    INTO v_project_id, v_max_score
    FROM public.project_submissions ps
    JOIN public.projects p ON p.id = ps.project_id
   WHERE ps.id = _submission_id;
  IF v_project_id IS NULL THEN
    RETURN;
  END IF;

  -- Sumar los `points` de los project_files (peso por pregunta).
  -- Si el proyecto no tiene archivos definidos o todos pesan 0,
  -- skipear (no hay nada que calcular sin denominador).
  SELECT COALESCE(SUM(points), 0)
    INTO v_total_points
    FROM public.project_files
   WHERE project_id = v_project_id;
  IF v_total_points <= 0 THEN
    RETURN;
  END IF;

  -- Sumar (ai_grade ponderado al cap de cada file).
  -- min(ai_grade, points) replica el cap del cliente. Si ai_grade
  -- IS NULL, cuenta como 0 (file sin calificar).
  SELECT COALESCE(SUM(LEAST(COALESCE(psf.ai_grade, 0), pf.points)), 0)
    INTO v_earned
    FROM public.project_submission_files psf
    JOIN public.project_files pf ON pf.id = psf.file_id
   WHERE psf.submission_id = _submission_id;

  v_new_sub_grade := ROUND((v_earned / v_total_points) * v_max_score, 2);

  -- Si ya hay defense_factor, recalcular final_grade. Si no, dejarlo
  -- como está (null o el valor anterior — la sustentación pendiente
  -- mantiene su estado).
  SELECT defense_factor INTO v_factor
    FROM public.project_submissions
   WHERE id = _submission_id;
  IF v_factor IS NOT NULL THEN
    v_new_final := ROUND(v_new_sub_grade * v_factor, 2);
  END IF;

  -- UPDATE. Importante: NO tocamos `status` — eso lo gestionan otros
  -- triggers/cliente (al guardar defensa, al recalificar, etc.).
  IF v_factor IS NOT NULL THEN
    UPDATE public.project_submissions
       SET submission_grade = v_new_sub_grade,
           final_grade = v_new_final,
           updated_at = now()
     W

