CREATE OR REPLACE FUNCTION public._tg_whiteboard_validate_session_course()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_session_course UUID;
BEGIN
  IF NEW.attendance_session_id IS NULL THEN
    RETURN NEW;
  END IF;
  IF NEW.course_id IS NULL THEN
    RAISE EXCEPTION 'Para asociar una pizarra a una sesión, primero hay que asociarla a un curso.';
  END IF;
  SELECT course_id INTO v_session_course
  FROM public.attendance_sessions
  WHERE id = NEW.attendance_session_id;
  IF v_session_course IS NULL THEN
    RAISE EXCEPTION 'La sesión asociada no existe o fue eliminada.';
  END IF;
  IF v_session_course <> NEW.course_id THEN
    RAISE EXCEPTION 'La sesión seleccionada pertenece a otro curso. Elegí una sesión del curso indicado.';
  END IF;
  RETURN NEW;
END
$function$

CREATE OR REPLACE FUNCTION public._tg_workshop_publish_notify()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _is_publish_event BOOLEAN := false;
  _is_edit_published BOOLEAN := false;
  _title TEXT;
  _body TEXT;
BEGIN
  -- Caso publicación: INSERT con status='published' O UPDATE de
  -- !='published' a 'published'.
  IF TG_OP = 'INSERT' AND NEW.status = 'published' THEN
    _is_publish_event := true;
  ELSIF TG_OP = 'UPDATE' AND NEW.status = 'published' AND OLD.status IS DISTINCT FROM 'published' THEN
    _is_publish_event := true;
  END IF;

  -- Caso edición post-publicación: UPDATE sobre fila ya publicada con
  -- cambios en campos significativos.
  IF TG_OP = 'UPDATE' AND NEW.status = 'published' AND OLD.status = 'published' THEN
    IF OLD.title IS DISTINCT FROM NEW.title
       OR OLD.instructions IS DISTINCT FROM NEW.instructions
       OR OLD.due_date IS DISTINCT FROM NEW.due_date
       OR OLD.start_date IS DISTINCT FROM NEW.start_date
       OR OLD.max_score IS DISTINCT FROM NEW.max_score
       OR OLD.max_attempts IS DISTINCT FROM NEW.max_attempts
    THEN
      _is_edit_published := true;
    END IF;
  END IF;

  IF NOT _is_publish_event AND NOT _is_edit_published THEN
    RETURN NULL;
  END IF;

  IF _is_publish_event THEN
    _title := 'Nuevo taller publicado';
    _body := COALESCE(NEW.title, 'Taller sin título') ||
             CASE WHEN NEW.due_date IS NOT NULL
                  THEN ' — entrega hasta ' || to_char(NEW.due_date, 'DD/MM/YYYY HH24:MI')
                  ELSE '' END;
  ELSE
    _title := 'Taller actualizado';
    _body := COALESCE(NEW.title, 'Taller') || ' fue modificado por el docente. Revisa los cambios.';
  END IF;

  PERFORM public.notify_course_students(
    NEW.course_id, _title, _body, 'workshop',
    '/app/student/workshops', 'Docente'
  );
  RETURN NULL;
END
$function$

CREATE OR REPLACE FUNCTION public._trg_audit_exam_submission()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_exam_title    text;
  v_course_id     uuid;
  v_course_name   text;
  v_student_email text;
  v_actor_id      uuid;
  v_actor_email   text;
  v_actor_role    text;
  v_action        text;
  v_severity      text := 'info';
BEGIN
  BEGIN
    SELECT e.title, e.course_id
      INTO v_exam_title, v_course_id
      FROM public.exams e WHERE e.id = NEW.exam_id;

    SELECT c.name INTO v_course_name
      FROM public.courses c WHERE c.id = v_course_id;

    SELECT au.email INTO v_student_email
      FROM auth.users au WHERE au.id = NEW.user_id;

    IF TG_OP = 'INSERT' THEN
      v_action      := 'submission.exam.started';
      v_actor_id    := NEW.user_id;
      v_actor_email := v_student_email;
      v_actor_role  := 'Estudiante';

    ELSE
      -- Solo loggeamos si hubo cambio de status o de nota.
      IF OLD.status IS NOT DISTINCT FROM NEW.status
         AND OLD.final_override_grade IS NOT DISTINCT FROM NEW.final_override_grade THEN
        RETURN NEW;
      END IF;

      IF OLD.status IS DISTINCT FROM NEW.status THEN
        CASE NEW.status
          WHEN 'completado' THEN
            v_action      := 'submission.exam.submitted';
            v_actor_id    := NEW.user_id;
            v_actor_email := v_student_email;
            v_actor_role  := 'Estudiante';
          WHEN 'sospechoso' THEN
            v_action      := 'submission.exam.flagged_suspicious';
            v_severity    := 'warning';
            v_actor_id    := COALESCE(public._audit_jwt_uid(), NEW.user_id);
            SELECT au.email INTO v_actor_email FROM auth.users au WHERE au.id = v_actor_id;
            v_actor_role  := 'sistema';
          ELSE
            -- Cambios a otros estados (en_progreso, etc.) no se loggean aqui.
            IF OLD.final_override_grade IS NOT DISTINCT FROM NEW.final_override_grade THEN
              RETURN NEW;
            END IF;
            -- Cae al bloque de cambio de nota mas abajo.
            v_action := NULL;
        END CASE;
      END IF;

