CREATE OR REPLACE FUNCTION public.acknowledge_rejected_ai_grading_job(_job_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _job RECORD;
  _caller UUID := auth.uid();
BEGIN
  IF _caller IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = '28000';
  END IF;

  SELECT id, status, created_by, acknowledged_at
    INTO _job
    FROM public.ai_grading_queue
   WHERE id = _job_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Job no encontrado' USING ERRCODE = 'P0001';
  END IF;

  -- Solo el docente que encolo el job puede cerrarlo. Admin/SuperAdmin
  -- también, por si necesitan limpiar como soporte.
  IF _job.created_by <> _caller
     AND NOT public.has_role(_caller, 'Admin'::public.app_role)
     AND NOT EXISTS (
       SELECT 1 FROM public.user_roles
        WHERE user_id = _caller AND role::text = 'SuperAdmin'
     ) THEN
    RAISE EXCEPTION 'Solo el docente del job (o Admin) puede cerrar el rechazo'
      USING ERRCODE = '42501';
  END IF;

  IF _job.status <> 'rejected' THEN
    RAISE EXCEPTION 'Solo se acusan rechazos (estado actual: %)', _job.status
      USING ERRCODE = 'P0001';
  END IF;

  IF _job.acknowledged_at IS NOT NULL THEN
    -- Ya estaba acusado; idempotente.
    RETURN;
  END IF;

  UPDATE public.ai_grading_queue
     SET acknowledged_at = now()
   WHERE id = _job_id;
END
$function$

CREATE OR REPLACE FUNCTION public.activate_ai_override(_code text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _code_row  RECORD;
  _expires   TIMESTAMPTZ;
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;
  IF NOT (public.has_role(auth.uid(), 'Docente') OR public.has_role(auth.uid(), 'Admin')) THEN
    RAISE EXCEPTION 'Solo Docente o Admin pueden activar override';
  END IF;

  SELECT * INTO _code_row
  FROM public.ai_override_codes
  WHERE code = _code AND revoked_at IS NULL
  FOR UPDATE;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'error', 'invalid_code');
  END IF;
  IF _code_row.expires_at IS NOT NULL AND _code_row.expires_at < now() THEN
    RETURN jsonb_build_object('ok', false, 'error', 'expired');
  END IF;
  IF _code_row.uses_count >= _code_row.max_uses THEN
    RETURN jsonb_build_object('ok', false, 'error', 'exhausted');
  END IF;

  _expires := now() + (_code_row.window_minutes || ' minutes')::interval;

  UPDATE public.ai_override_codes
     SET uses_count = uses_count + 1
   WHERE id = _code_row.id;

  INSERT INTO public.ai_override_activations (code_id, user_id, expires_at)
  VALUES (_code_row.id, auth.uid(), _expires);

  RETURN jsonb_build_object(
    'ok', true,
    'expires_at', _expires,
    'window_minutes', _code_row.window_minutes,
    'max_messages_per_activation', _code_row.max_messages_per_activation,
    'remaining', _code_row.max_messages_per_activation
  );
END
$function$

CREATE OR REPLACE FUNCTION public.add_business_days(_start date, _n integer)
 RETURNS date
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE d date := _start; rem int := GREATEST(COALESCE(_n, 0), 0);
BEGIN
  IF _start IS NULL THEN RETURN NULL; END IF;
  WHILE rem > 0 LOOP
    d := d + 1;
    IF EXTRACT(ISODOW FROM d) < 6                                   -- 1..5 = lun..vie
       AND NOT EXISTS (SELECT 1 FROM public.platform_holidays h WHERE h.holiday_date = d)
    THEN rem := rem - 1;
    END IF;
  END LOOP;
  RETURN d;
END $function$

CREATE OR REPLACE FUNCTION public.add_questions_from_bank_to_exam(_bank_ids uuid[], _exam_id uuid, _points_override jsonb DEFAULT '{}'::jsonb)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _max_pos INT;
  _inserted INT := 0;
  _bank RECORD;
  _custom_points NUMERIC;
BEGIN
  -- Validación: el usuario debe ser docente del curso del examen o admin.
  IF NOT (
    public.is_admin_of_course_tenant((SELECT e2.course_id FROM public.exams e2 WHERE e2.id = _exam_id)) OR EXISTS (
      SELECT 1 FROM public.exams e
      JOIN public.course_teachers ct ON ct.course_id = e.course_id
      WHERE e.id = _exam_id AND ct.user_id = auth.uid()
    )
  ) THEN
    RAISE EXCEPTION 'No autorizado para modificar este examen';
  END IF;

  SELECT COALESCE(MAX(position), -1) INTO _max_pos
    FROM public.questions WHERE exam_id = _exam_id;

  FOR _bank IN
    SELECT b.* FROM public.question_bank b
    WHERE b.id = ANY(_bank_ids)
    -- Tipo codigo_zip no aplica a examen (es solo para proyectos).
    AND b.type <> 'codigo_zip'
    -- El usuario también debe ver el banco (RLS lo refuerza).
    AND (
      public.is_admin_of_course_tenant(b.course_id) OR EXISTS (
        SELECT 1 FROM public.course_teachers ct
        WHERE ct.course_id = b.course_id AND ct.user_id = auth.uid()
      )
    )
  LOOP
    _custom_points := COALESCE(
      (_points_override->>(_bank.id::text))::numeric,
      _bank.suggested_points
    );
    _max_pos := _max_pos + 1;

    INSERT INTO public.questions (
      exam_id, type, content, options, expected_rubric,
      language, starter_code, points, position
    ) VALUES (
      _exam_id, _bank.type, _bank.content, _bank.options, _bank.expected_rubric,
      _bank.language, _bank.starter_code, _custom_points, _max_pos
    );

    -- Trackear uso
    UPDATE public.question_bank
      SET times_used = times_used + 1, last_used_at = now()
      WHERE id = _bank.id;
    _inserted := _inserted + 1;
  END LOOP;

  RETURN _inserted;
END
$function$

