 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _path TEXT;
BEGIN
  IF NOT public.is_super_admin() THEN
    RAISE EXCEPTION 'Solo SuperAdmin puede borrar backups (infra cross-tenant)';
  END IF;

  SELECT file_path INTO _path FROM public.db_backups WHERE id = _id;
  IF _path IS NOT NULL THEN
    DELETE FROM storage.objects WHERE bucket_id = 'db-backups' AND name = _path;
  END IF;
  DELETE FROM public.db_backups WHERE id = _id;
END
$function$

CREATE OR REPLACE FUNCTION public.admin_enqueue_db_backup(_tables text[], _label text DEFAULT NULL::text, _source text DEFAULT 'manual'::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _id UUID;
BEGIN
  IF NOT public.is_super_admin() THEN
    RAISE EXCEPTION 'Solo SuperAdmin puede crear backups (infra cross-tenant)';
  END IF;
  IF _tables IS NULL OR array_length(_tables, 1) IS NULL OR array_length(_tables, 1) = 0 THEN
    RAISE EXCEPTION 'Debes elegir al menos una tabla';
  END IF;
  IF _source NOT IN ('manual', 'cron') THEN
    RAISE EXCEPTION 'source debe ser manual o cron';
  END IF;

  INSERT INTO public.db_backups (tables, label, source, status, created_by)
  VALUES (_tables, _label, _source, 'queued', auth.uid())
  RETURNING id INTO _id;

  RETURN _id;
END
$function$

CREATE OR REPLACE FUNCTION public.admin_release_stuck_ai_jobs(_threshold_minutes integer DEFAULT 5)
 RETURNS TABLE(released_to_pending integer, released_to_failed integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;
  IF NOT (public.has_role(auth.uid(), 'Admin') OR public.is_super_admin()) THEN
    RAISE EXCEPTION 'Solo Admin o SuperAdmin pueden liberar jobs atascados';
  END IF;

  _threshold_minutes := GREATEST(1, LEAST(120, COALESCE(_threshold_minutes, 5)));

  RETURN QUERY
    SELECT r.released_to_pending, r.released_to_failed
      FROM public.release_stuck_processing_jobs(_threshold_minutes, 3) AS r;
END;
$function$

CREATE OR REPLACE FUNCTION public.admin_set_cron_job_active(_jobid bigint, _active boolean)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'cron'
AS $function$
DECLARE
  v_cron_exists BOOLEAN;
  v_jobname     TEXT;
BEGIN
  IF NOT public.has_role(auth.uid(), 'SuperAdmin') THEN
    RAISE EXCEPTION 'Solo SuperAdmin puede modificar cron jobs (infra cross-tenant)';
  END IF;

  SELECT EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'cron') INTO v_cron_exists;
  IF NOT v_cron_exists THEN
    RAISE EXCEPTION 'pg_cron no está instalado en este proyecto';
  END IF;

  SELECT jobname INTO v_jobname FROM cron.job WHERE jobid = _jobid;
  IF v_jobname IS NULL THEN
    RAISE EXCEPTION 'No existe el cron job con jobid=%', _jobid;
  END IF;

  PERFORM cron.alter_job(job_id := _jobid, active := _active);

  PERFORM public.log_audit_event(
    p_action      => CASE WHEN _active THEN 'cron.activated' ELSE 'cron.deactivated' END,
    p_category    => 'system',
    p_severity    => 'info',
    p_entity_type => 'cron_job',
    p_entity_id   => _jobid::text,
    p_entity_name => v_jobname,
    p_metadata    => jsonb_build_object('active', _active)
  );

  RETURN TRUE;
END
$function$

CREATE OR REPLACE FUNCTION public.admin_update_cron_job_schedule(_jobid bigint, _schedule text)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'cron'
AS $function$
DECLARE
  v_cron_exists BOOLEAN;
  v_jobname     TEXT;
  v_old         TEXT;
  v_tokens      INTEGER;
BEGIN
  IF NOT public.has_role(auth.uid(), 'SuperAdmin') THEN
    RAISE EXCEPTION 'Solo SuperAdmin puede modificar cron jobs (infra cross-tenant)';
  END IF;

  SELECT EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'cron') INTO v_cron_exists;
  IF NOT v_cron_exists THEN
    RAISE EXCEPTION 'pg_cron no está instalado en este proyecto';
  END IF;

  IF _schedule IS NULL OR length(trim(_schedule)) = 0 THEN
    RAISE EXCEPTION 'La expresión cron no puede estar vacía';
  END IF;

  v_tokens := array_length(string_to_array(trim(regexp_replace(_schedule, '\s+', ' ', 'g')), ' '), 1);
  IF NOT (
    v_tokens IN (5, 6)
    OR _schedule ~ '^@(hourly|daily|weekly|monthly|yearly|annually|reboot)$'
  ) THEN
    RAISE EXCEPTION 'Expresión cron inválida: "%". Esperaba 5 campos ("m h dom mon dow") o un alias @hourly/@daily/...', _schedule;
  END IF;

  SELECT jobname, schedule INTO v_jobname, v_old FROM cron.job WHERE jobid = _jobid;
  IF v_jobname IS NULL THEN
    RAISE EXCEPTION 'No existe el cron job con jobid=%', _jobid;
  END IF;

  PERFORM cron.alter_job(job_id := _jobid, schedule := _schedule);

  PERFORM public.log_audit_event(
    p_action      => 'cron.schedule_updated',
    p_category    => 'system',
    p_severity    => 'info',
    p_entity_type => 'cron_job',
    p_entity_id   => _jobid::text,
    p_entity_name => v_jobname,
    p_metadata    => jsonb_build_object('old_schedule', v_old, 'new_schedule', _schedule)
  );

  RETURN TRUE;
END
$function$

