CREATE OR REPLACE FUNCTION public.apply_email_change_now(_token_id uuid)
 RETURNS TABLE(previous_email text, apply_after timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_row RECORD;
  v_old_email TEXT;
  v_apply_after TIMESTAMPTZ;
BEGIN
  -- Lock + validar.
  SELECT id, user_id, new_email, used_at, expires_at, confirmed_at,
         cancelled_at, applied_at
    INTO v_row
    FROM public.email_change_tokens
   WHERE id = _token_id
   FOR UPDATE;

  IF v_row IS NULL THEN
    RAISE EXCEPTION 'token_not_found' USING ERRCODE = 'P0001';
  END IF;
  IF v_row.used_at IS NOT NULL OR v_row.applied_at IS NOT NULL THEN
    RAISE EXCEPTION 'token_already_used' USING ERRCODE = 'P0001';
  END IF;
  IF v_row.cancelled_at IS NOT NULL THEN
    RAISE EXCEPTION 'token_cancelled' USING ERRCODE = 'P0001';
  END IF;
  IF v_row.expires_at < NOW() THEN
    RAISE EXCEPTION 'token_expired' USING ERRCODE = 'P0001';
  END IF;

  -- Re-check de unicidad del new_email (race window desde el request).
  IF EXISTS (
    SELECT 1 FROM auth.users
    WHERE LOWER(email) = LOWER(v_row.new_email)
      AND id <> v_row.user_id
  ) THEN
    RAISE EXCEPTION 'email_already_taken' USING ERRCODE = 'P0001';
  END IF;

  -- Capturar el email actual (= previous_email).
  SELECT email INTO v_old_email FROM auth.users WHERE id = v_row.user_id;
  IF v_old_email IS NULL THEN
    RAISE EXCEPTION 'user_not_found' USING ERRCODE = 'P0001';
  END IF;

  v_apply_after := NOW() + INTERVAL '24 hours';

  -- Aplicar el cambio.
  UPDATE auth.users
     SET email = v_row.new_email,
         email_confirmed_at = COALESCE(email_confirmed_at, NOW()),
         updated_at = NOW()
   WHERE id = v_row.user_id;

  UPDATE public.profiles
     SET institutional_email = v_row.new_email
   WHERE id = v_row.user_id;

  -- Marcar el token: confirmed + applied + previous_email guardado +
  -- apply_after (ahora = deadline de revert).
  UPDATE public.email_change_tokens
     SET confirmed_at = NOW(),
         applied_at = NOW(),
         apply_after = v_apply_after,
         previous_email = v_old_email
   WHERE id = v_row.id;

  -- Audit.
  INSERT INTO public.aud

CREATE OR REPLACE FUNCTION public.cancel_ai_grading_job(_job_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _job RECORD;
  _caller UUID := auth.uid();
  _authorized BOOLEAN := false;
BEGIN
  IF _caller IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;

  SELECT id, status, course_id, created_by
    INTO _job
    FROM public.ai_grading_queue
   WHERE id = _job_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Job no encontrado';
  END IF;

  IF public.is_super_admin()
     OR (_job.course_id IS NOT NULL AND public.is_admin_of_course_tenant(_job.course_id)) THEN
    _authorized := true;
  ELSIF _job.created_by = _caller THEN
    _authorized := true;
  ELSIF _job.course_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.course_teachers ct
    WHERE ct.course_id = _job.course_id AND ct.user_id = _caller
  ) THEN
    _authorized := true;
  END IF;

  IF NOT _authorized THEN
    RAISE EXCEPTION 'No tienes permiso para cancelar este job';
  END IF;

  IF _job.status NOT IN ('pending', 'failed', 'processing') THEN
    RAISE EXCEPTION 'Solo se pueden cancelar jobs en estado pending, failed o processing (estado actual: %)', _job.status;
  END IF;

  UPDATE public.ai_grading_queue
     SET status = 'cancelled',
         completed_at = COALESCE(completed_at, now())
   WHERE id = _job_id;
END
$function$

