  -- destino). El enforce_single

CREATE OR REPLACE FUNCTION public.check_email_taken(p_email text, p_exclude_user_id uuid DEFAULT NULL::uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_email TEXT := LOWER(TRIM(p_email));
  v_found BOOLEAN;
BEGIN
  IF v_email IS NULL OR v_email = '' THEN
    RETURN FALSE;
  END IF;

  -- Buscar en institutional_email
  SELECT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE LOWER(institutional_email) = v_email
      AND (p_exclude_user_id IS NULL OR id <> p_exclude_user_id)
  ) INTO v_found;
  IF v_found THEN RETURN TRUE; END IF;

  -- Buscar en personal_email
  SELECT EXISTS (
    SELECT 1 FROM public.profiles
    WHERE LOWER(personal_email) = v_email
      AND (p_exclude_user_id IS NULL OR id <> p_exclude_user_id)
  ) INTO v_found;
  IF v_found THEN RETURN TRUE; END IF;

  -- Buscar en auth.users.email — atrapa el caso "alguien se registró
  -- con este correo pero su profile aún no se sincronizó", aunque el
  -- trigger handle_new_user típicamente lo crea de inmediato.
  SELECT EXISTS (
    SELECT 1 FROM auth.users
    WHERE LOWER(email) = v_email
      AND (p_exclude_user_id IS NULL OR id <> p_exclude_user_id)
  ) INTO v_found;
  RETURN v_found;
END;
$function$

CREATE OR REPLACE FUNCTION public.check_rate_limit(p_action text, p_max integer, p_window_seconds integer)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid     uuid := auth.uid();
  v_count   int;
  v_oldest  timestamptz;
BEGIN
  IF v_uid IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'error', 'unauthenticated', 'remaining', 0);
  END IF;

  -- Cuenta eventos dentro de la ventana.
  SELECT count(*), min(created_at)
    INTO v_count, v_oldest
    FROM public.rate_limit_events
    WHERE actor_id = v_uid
      AND action = p_action
      AND created_at >= now() - make_interval(secs => p_window_seconds);

  IF v_count >= p_max THEN
    RETURN jsonb_build_object(
      'ok', false,
      'error', 'rate_limited',
      'remaining', 0,
      'retry_after_seconds',
        GREATEST(
          1,
          extract(epoch FROM (v_oldest + make_interval(secs => p_window_seconds) - now()))::int
        ),
      'limit', p_max,
      'window_seconds', p_window_seconds
    );
  END IF;

  INSERT INTO public.rate_limit_events (actor_id, action) VALUES (v_uid, p_action);

  RETURN jsonb_build_object(
    'ok', true,
    'remaining', p_max - v_count - 1,
    'limit', p_max,
    'window_seconds', p_window_seconds
  );
END;
$function$

CREATE OR REPLACE FUNCTION public.claim_ai_override_message()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _activation_id UUID;
  _cap INT;
  _consumed INT;
  _expires TIMESTAMPTZ;
BEGIN
  IF auth.uid() IS NULL THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'unauthenticated');
  END IF;

  -- Selección con FOR UPDATE evita race entre dos requests concurrentes
  -- del mismo user (e.g. dos pestañas calificando en paralelo).
  SELECT a.id, c.max_messages_per_activation, a.messages_consumed, a.expires_at
    INTO _activation_id, _cap, _consumed, _expires
    FROM public.ai_override_activations a
    JOIN public.ai_override_codes c ON c.id = a.code_id
   WHERE a.user_id = auth.uid() AND a.expires_at > now()
   ORDER BY a.activated_at DESC
   LIMIT 1
   FOR UPDATE OF a;

  IF NOT FOUND THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'no_active_override');
  END IF;

  -- Cap NULL = ilimitado (legacy + valor por defecto).
  IF _cap IS NOT NULL AND _consumed >= _cap THEN
    RETURN jsonb_build_object('ok', false, 'reason', 'cap_reached', 'consumed', _consumed, 'cap', _cap);
  END IF;

  UPDATE public.ai_override_activations
     SET messages_consumed = messages_consumed + 1
   WHERE id = _activation_id;

  RETURN jsonb_build_object(
    'ok', true,
    'consumed', _consumed + 1,
    'cap', _cap,
    'remaining', CASE WHEN _cap IS NULL THEN NULL ELSE _cap - (_consumed + 1) END,
    'expires_at', _expires
  );
END
$function$

CREATE OR REPLACE FUNCTION public.clear_group_chat(_group_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_me UUID := auth.uid();
  v_now TIMESTAMPTZ := now();
  v_course UUID;
BEGIN
  IF v_me IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = '28000';
  END IF;
  IF NOT public.is_group_chat_member(_group_id, v_me) THEN
    RAISE EXCEPTION 'No eres miembro del chat' USING ERRCODE = '42501';
  END IF;

  SELECT course_id INTO v_course FROM public.group_chats WHERE id = _group_id;

  -- Si es chat de curso y no tengo row en members, insertamos lazy.
  IF v_course IS NOT NULL THEN
    INSERT INTO public.group_chat_members (group_id, user_id, cleared_at)
    VALUES (_group_id, v_me, v_now)
    ON CONFLICT (group_id, user_id) DO UPDATE SET cleared_at = v_now;
  ELSE
    UPDATE public.group_chat_members
    SET cleared_at = v_now
    WHERE group_id = _group_id AND user_id = v_me;
  END IF;
END;
$function$

