CREATE OR REPLACE FUNCTION public.close_checkin_for_course(_course_id uuid)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE v_count int := 0;
BEGIN
  IF to_regclass('public.attendance_sessions') IS NULL THEN RETURN 0; END IF;
  WITH upd AS (
    UPDATE public.attendance_sessions
       SET check_in_open = false
     WHERE course_id = _course_id
       AND check_in_open = true
       AND deleted_at IS NULL
    RETURNING id
  ) SELECT count(*) INTO v_count FROM upd;
  IF to_regclass('public.attendance_check_in_state') IS NOT NULL THEN
    DELETE FROM public.attendance_check_in_state
     WHERE session_id IN (SELECT id FROM public.attendance_sessions WHERE course_id = _course_id);
  END IF;
  RETURN v_count;
END $function$

CREATE OR REPLACE FUNCTION public.delete_ai_grading_job(_job_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _job RECORD;
  _caller UUID := auth.uid();
  _authorized BOOLEAN := false;
BEGIN
  IF _caller IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;

  SELECT id, course_id, created_by
    INTO _job
    FROM public.ai_grading_queue
   WHERE id = _job_id;

  IF NOT FOUND THEN
    -- Idempotente: si ya no existe, no es un error (otra pestaña lo borró).
    RETURN;
  END IF;

  IF public.has_role(_caller, 'Admin') OR public.is_super_admin() THEN
    _authorized := true;
  ELSIF _job.created_by = _caller THEN
    _authorized := true;
  ELSIF _job.course_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.course_teachers ct
    WHERE ct.course_id = _job.course_id AND ct.user_id = _caller
  ) THEN
    _authorized := true;
  END IF;

  IF NOT _authorized THEN
    RAISE EXCEPTION 'No tienes permiso para eliminar este job';
  END IF;

  DELETE FROM public.ai_grading_queue WHERE id = _job_id;
END
$function$

CREATE OR REPLACE FUNCTION public.dispatch_scheduled_messages()
 RETURNS integer
