CREATE OR REPLACE FUNCTION public.get_or_create_calendar_token()
 RETURNS TABLE(token text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _user uuid := auth.uid();
  _row record;
  _new_token text;
  i INT;
BEGIN
  IF _user IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;

  SELECT tbl.token AS tok, tbl.created_at AS ts INTO _row
    FROM public.student_calendar_tokens tbl
    WHERE tbl.user_id = _user AND tbl.revoked_at IS NULL
    LIMIT 1;

  IF FOUND THEN
    -- `token` y `created_at` aquí refieren a las columnas OUT del
    -- RETURNS TABLE; las llenamos con los valores del registro.
    token := _row.tok;
    created_at := _row.ts;
    RETURN NEXT;
    RETURN;
  END IF;

  FOR i IN 1..10 LOOP
    _new_token := translate(
      encode(extensions.gen_random_bytes(24), 'base64'),
      '+/=', '-_'
    );
    _new_token := substring(_new_token, 1, 32);
    EXIT WHEN NOT EXISTS (
      SELECT 1 FROM public.student_calendar_tokens tbl
       WHERE tbl.token = _new_token
    );
  END LOOP;

  INSERT INTO public.student_calendar_tokens (user_id, token)
    VALUES (_user, _new_token);

  token := _new_token;
  created_at := now();
  RETURN NEXT;
END;
$function$

CREATE OR REPLACE FUNCTION public.group_chat_member_ids(_group uuid)
 RETURNS TABLE(user_id uuid)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_course UUID;
BEGIN
  SELECT course_id INTO v_course FROM public.group_chats WHERE id = _group;
  IF v_course IS NOT NULL THEN
    RETURN QUERY
      SELECT DISTINCT u FROM (
        SELECT user_id AS u FROM public.course_teachers WHERE course_id = v_course
        UNION
        SELECT user_id AS u FROM public.course_enrollments WHERE course_id = v_course
      ) s;
  ELSE
    RETURN QUERY SELECT user_id FROM public.group_chat_members WHERE group_id = _group;
  END IF;
END;
$function$

