CREATE OR REPLACE FUNCTION public.insert_broadcast_messages(_sender_id uuid, _conv_ids uuid[], _body text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller UUID := auth.uid();
  v_inserted INT;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = '28000';
  END IF;
  IF v_caller <> _sender_id THEN
    RAISE EXCEPTION 'sender_id debe coincidir con auth.uid()' USING ERRCODE = '42501';
  END IF;
  IF _conv_ids IS NULL OR cardinality(_conv_ids) = 0 THEN
    RETURN 0;
  END IF;
  IF _body IS NULL OR length(_body) = 0 THEN
    RAISE EXCEPTION 'body vacío' USING ERRCODE = '22023';
  END IF;
  IF length(_body) > 4000 THEN
    _body := substring(_body FROM 1 FOR 4000);
  END IF;

  -- Saltarse el trigger de "nueva conversación" notif: la edge ya
  -- maneja sus propias notificaciones de broadcast.
  PERFORM set_config('app.skip_message_notif', 'true', true);

  INSERT INTO public.messages (conversation_id, sender_id, body)
  SELECT conv_id, _sender_id, _body
    FROM unnest(_conv_ids) AS conv_id;

  GET DIAGNOSTICS v_inserted = ROW_COUNT;
  RETURN v_inserted;
END;
$function$

CREATE OR REPLACE FUNCTION public.is_group_chat_member(_group uuid, _user uuid)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_course UUID;
BEGIN
  IF _group IS NULL OR _user IS NULL THEN
    RETURN FALSE;
  END IF;
  SELECT course_id INTO v_course FROM public.group_chats WHERE id = _group;
  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;
  IF v_course IS NOT NULL THEN
    -- Membresía dinámica via curso. Admin tiene acceso global aunque no
    -- esté matriculado (consistente con can_message).
    RETURN public.has_role(_user, 'Admin'::public.app_role)
      OR EXISTS (SELECT 1 FROM public.course_teachers WHERE course_id = v_course AND user_id = _user)
      OR EXISTS (SELECT 1 FROM public.course_enrollments WHERE course_id = v_course AND user_id = _user);
  ELSE
    RETURN EXISTS (
      SELECT 1 FROM public.group_chat_members
      WHERE group_id = _group AND user_id = _user
    );
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.issue_certificate(_user_id uuid, _course_id uuid, _final_grade numeric)
 RETURNS uuid
 LANGUAGE plpgsql
