        USING ERRCODE = 'P0001';
    END IF;
    LOOP
      v_pin := lpad((floor(random() * 1000000))::int::text, 6, '0');
      EXIT WHEN NOT EXISTS (SELECT 1 FROM public.kahoot_games WHERE pin = v_pin AND status <> 'ended');
    END LOOP;
