CREATE OR REPLACE FUNCTION public.log_audit_event(p_action text, p_category text, p_severity text DEFAULT 'info'::text, p_entity_type text DEFAULT NULL::text, p_entity_id text DEFAULT NULL::text, p_entity_name text DEFAULT NULL::text, p_course_id uuid DEFAULT NULL::uuid, p_course_name text DEFAULT NULL::text, p_metadata jsonb DEFAULT '{}'::jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_email text;
  v_role  text;
BEGIN
  SELECT email INTO v_email FROM auth.users WHERE id = auth.uid();
  SELECT role::text INTO v_role FROM public.user_roles WHERE user_id = auth.uid() LIMIT 1;

  INSERT INTO public.audit_logs (
    actor_id, actor_email, actor_role,
    action, category, severity,
    entity_type, entity_id, entity_name,
    course_id, course_name,
    metadata
  ) VALUES (
    auth.uid(), v_email, COALESCE(v_role, 'Estudiante'),
    p_action, p_category, p_severity,
    p_entity_type, p_entity_id, p_entity_name,
    p_course_id, p_course_name,
    COALESCE(p_metadata, '{}')
  );
EXCEPTION WHEN OTHERS THEN
  NULL;
END;
$function$

CREATE OR REPLACE FUNCTION public.mark_ai_suspicion_reviewed(p_kind text, p_submission_id uuid, p_unmark boolean DEFAULT false)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NOT (public.has_role(auth.uid(), 'Admin') OR public.has_role(auth.uid(), 'Docente')) THEN
    RAISE EXCEPTION 'Solo docentes/admins pueden marcar sospechas como revisadas';
  END IF;
  IF p_kind = 'exam' THEN
    IF p_unmark THEN
      UPDATE public.submissions SET ai_review_at = NULL, ai_review_by = NULL WHERE id = p_submission_id;
    ELSE
      UPDATE public.submissions
         SET ai_review_at = COALESCE(ai_review_at, now()),
             ai_review_by = COALESCE(ai_review_by, auth.uid())
       WHERE id = p_submission_id;
    END IF;
  ELSIF p_kind = 'workshop' THEN
    IF p_unmark THEN
      UPDATE public.workshop_submissions SET ai_review_at = NULL, ai_review_by = NULL WHERE id = p_submission_id;
    ELSE
      UPDATE public.workshop_submissions
         SET ai_review_at = COALESCE(ai_review_at, now()),
             ai_review_by = COALESCE(ai_review_by, auth.uid())
       WHERE id = p_submission_id;
    END IF;
  ELSIF p_kind = 'project' THEN
    IF p_unmark THEN
      UPDATE public.project_submissions SET ai_review_at = NULL, ai_review_by = NULL WHERE id = p_submission_id;
    ELSE
      UPDATE public.project_submissions
         SET ai_review_at = COALESCE(ai_review_at, now()),
             ai_review_by = COALESCE(ai_review_by, auth.uid())
       WHERE id = p_submission_id;
    END IF;
  ELSE
    RAISE EXCEPTION 'kind invalido: %', p_kind;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.mark_all_conversations_read()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid   uuid := auth.uid();
  v_count integer := 0;
  v_now   timestamptz := NOW();
  v_a_cnt integer;
  v_b_cnt integer;
BEGIN
  IF v_uid IS NULL THEN
    RETURN 0;
  END IF;

  -- Actualiza el lado A: las conversaciones donde soy user_a y tengo
  -- last_read_at más viejo que NOW (siempre cierto). UPDATE incondicional
  -- — más simple que filtrar por mensajes nuevos pendientes, y mover
  -- el timestamp un segundo más adelante en convs ya al día no rompe
  -- nada (sigue siendo "leído hasta ahora").
  UPDATE public.conversations
     SET user_a_last_read_at = v_now
   WHERE user_a = v_uid;
  GET DIAGNOSTICS v_a_cnt = ROW_COUNT;

  UPDATE public.conversations
     SET user_b_last_read_at = v_now
   WHERE user_b = v_uid;
  GET DIAGNOSTICS v_b_cnt = ROW_COUNT;

  v_count := v_a_cnt + v_b_cnt;
  RETURN v_count;
END;
$function$

CREATE OR REPLACE FUNCTION public.mark_forum_reply_official(_reply_id uuid, _official boolean DEFAULT true)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _thread_id UUID;
  _course_id UUID;
BEGIN
  SELECT r.thread_id, t.course_id
    INTO _thread_id, _course_id
    FROM public.forum_replies r
    JOIN public.forum_threads t ON t.id = r.thread_id
    WHERE r.id = _reply_id;
  IF _thread_id IS NULL THEN
    RAISE EXCEPTION 'Respuesta no encontrada';
  END IF;

  IF NOT (
    public.has_role(auth.uid(), 'Admin')
    OR EXISTS (
      SELECT 1 FROM public.course_teachers
      WHERE course_id = _course_id AND user_id = auth.uid()
    )
  ) THEN
    RAISE EXCEPTION 'Solo el docente del curso o admin pueden marcar respuestas como oficiales';
  END IF;

  IF _official THEN
    -- Quitar oficial a cualquier otra del mismo hilo
    UPDATE public.forum_replies SET is_official = FALSE
      WHERE thread_id = _thread_id AND id <> _reply_id AND is_official = TRUE;
    UPDATE public.forum_replies SET is_official = TRUE WHERE id = _reply_id;
    UPDATE public.forum_threads SET official_reply_id = _reply_id WHERE id = _thread_id;
  ELSE
    UPDATE public.forum_replies SET is_official = FALSE WHERE id = _reply_id;
    UPDATE public.forum_threads SET official_reply_id = NULL
      WHERE id = _thread_id AND official_reply_id = _reply_id;
  END IF;
END
$function$

CREATE OR REPLACE FUNCTION public.mark_group_chat_read(_group_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_me UUID := auth.uid();
  v_now TIMESTAMPTZ := now();
  v_course UUID;
BEGIN
  IF v_me IS NULL THEN RETURN; END IF;
  IF NOT public.is_group_chat_member(_group_id, v_me) THEN RETURN; END IF;
  SELECT course_id INTO v_course FROM public.group_chats WHERE id = _group_id;
  IF v_course IS NOT NULL THEN
    INSERT INTO public.group_chat_members (group_id, user_id, last_read_at)
    VALUES (_group_id, v_me, v_now)
    ON CONFLICT (group_id, user_id) DO UPDATE SET last_read_at = v_now;
  ELSE
    UPDATE public.group_chat_members
    SET last_read_at = v_now
    WHERE group_id = _group_id AND user_id = v_me;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.mark_project_video_watched(_submission_id uuid, _video_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_user UUID := auth.uid();
  v_owner UUID;
  v_group_id UUID;
  v_project_id UUID;
  v_video_project UUID;
BEGIN
  IF v_user IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;

  -- Validar que el caller es dueño de la submission (o miembro del grupo).
  SELECT user_id, group_id, project_id
    INTO v_owner, v_group_id, v_project_id
    FROM public.project_submissions
   WHERE id = _submission_id;
  IF v_project_id IS NULL THEN
    RAISE EXCEPTION 'Submission no encontrada';
  END IF;
  IF v_owner <> v_user
     AND NOT EXISTS (
       SELECT 1 FROM public.project_group_members
        WHERE group_id = v_group_id AND user_id = v_user
     )
  THEN
    RAISE EXCEPTION 'No tienes permiso para marcar esta submission';
  END IF;

  -- Validar que el video pertenece al mismo proyecto que la submission
  -- (defensa contra IDs mezclados desde el cliente).
  SELECT project_id INTO v_video_project
    FROM public.project_intro_videos
   WHERE id = _video_id;
  IF v_video_project IS NULL THEN
    RAISE EXCEPTION 'Video no encontrado';
  END IF;
  IF v_video_project <> v_project_id THEN
    RAISE EXCEPTION 'El video no pertenece al proyecto de esta submission';
  END IF;

  INSERT INTO public.project_submission_video_views (submission_id, video_id, watched_at)
  VALUES (_submission_id, _video_id, now())
  ON CONFLICT (submission_id, video_id) DO NOTHING;

  -- Compat: también actualizamos `video_watched_at` legacy cuando se
  -- alcanza el último video. El campo se usaba como "todos vistos" en
  -- código viejo; mientras no migremos todos los callers, lo mantenemos
  -- en sync con el conteo real.
  IF (
    SELECT count(*) FROM public.project_submission_video_views
     WHERE submission_id = _submission_id
  ) >= (
    SELECT count(*) FROM public.project_intro_videos
     WHERE project_id = v_project_id
  ) THEN
    UPDATE public.project_submissions
       SET video_watched_at = COALESCE(video_watched_at, now())
     WHERE id = _submission_id;
  END IF;
END
$funct

