CREATE OR REPLACE FUNCTION public.notify_admins_storage_threshold()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _settings   record;
  _usage      record;
  _db_used_pct      numeric;
  _storage_used_pct numeric;
  _used_threshold   numeric;  -- = 100 - alert_threshold_pct
  _admin_id   uuid;
  _count      int := 0;
  _title      text;
  _body       text;
  _parts      text[] := ARRAY[]::text[];
BEGIN
  SELECT * INTO _settings FROM public.system_settings WHERE id = 1;
  IF _settings IS NULL THEN
    RETURN 0;
  END IF;

  SELECT * INTO _usage FROM public.system_storage_usage();
  _used_threshold := 100 - _settings.alert_threshold_pct;

  _db_used_pct := CASE WHEN _settings.db_quota_mb > 0
    THEN (_usage.db_size_bytes::numeric / (_settings.db_quota_mb::numeric * 1024 * 1024)) * 100
    ELSE 0 END;
  _storage_used_pct := CASE WHEN _settings.storage_quota_mb > 0
    THEN (_usage.objects_size_bytes::numeric / (_settings.storage_quota_mb::numeric * 1024 * 1024)) * 100
    ELSE 0 END;

  -- Si ningún recurso supera el threshold, salimos sin alertar.
  IF _db_used_pct <= _used_threshold AND _storage_used_pct <= _used_threshold THEN
    RETURN 0;
  END IF;

  IF _db_used_pct > _used_threshold THEN
    _parts := _parts || format(
      'Base de datos: %s%% usado (%s MB / %s MB)',
      ROUND(_db_used_pct, 1),
      ROUND(_usage.db_size_bytes::numeric / (1024 * 1024), 1),
      _settings.db_quota_mb
    );
  END IF;
  IF _storage_used_pct > _used_threshold THEN
    _parts := _parts || format(
      'Storage: %s%% usado (%s MB / %s MB · %s objetos)',
      ROUND(_storage_used_pct, 1),
      ROUND(_usage.objects_size_bytes::numeric / (1024 * 1024), 1),
      _settings.storage_quota_mb,
      _usage.objects_count
    );
  END IF;

  _title := 'Alerta de espacio del sistema';
  _body := 'Algunos recursos están por encima del umbral de ' ||
           (100 - _settings.alert_threshold_pct) || '% usado:' || E'\n• ' ||
           array_to_string(_parts, E'\n• ') ||
           E'\n\nEntra al panel de Sistema para revisar y considerar limpieza o ' ||
           'upgrade del plan.';

  -- Notificar a CADA Admin. Idempote

CREATE OR REPLACE FUNCTION public.notify_course_enrollment_welcome()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  DECLARE
    v_course_name text;
    v_deleted     timestamptz;
    v_status      text;
  BEGIN
    -- Defensivo: NADA acá debe abortar la inscripción. Si algo falla, la matrícula
    -- queda intacta y solo se pierde el correo de bienvenida.
    BEGIN
      SELECT name, deleted_at, status
        INTO v_course_name, v_deleted, v_status
        FROM public.courses WHERE id = NEW.course_id;

      -- Curso inexistente o en papelera → no dar bienvenida (no se debe notificar
      -- a un alumno sobre un curso soft-deleted; ver regla universal de Papelera).
      IF v_course_name IS NULL OR v_deleted IS NOT NULL THEN
        RETURN NEW;
      END IF;

      -- Curso en BORRADOR → todavía no publicado; la bienvenida saldrá al publicar
      -- (trg_course_published_welcome). Matricular en borrador NO debe emailar.
      IF v_status = 'borrador' THEN
        RETURN NEW;
      END IF;

      INSERT INTO public.notifications (user_id, title, body, kind, link)
      VALUES (
        NEW.user_id,
        '🎓 Bienvenido a ' || v_course_name,
        'Fuiste inscrito en el curso "' || v_course_name ||
          '". Ya puedes ver su contenido, clases, talleres y evaluaciones desde Mis cursos.',
        'course_welcome',
        '/app/student/courses'
      );
    EXCEPTION WHEN OTHERS THEN
      -- Swallow: la inscripción es más importante que el correo de bienvenida.
      NULL;
    END;
    RETURN NEW;
  END;
  $function$

CREATE OR REPLACE FUNCTION public.notify_feedback_event(_thread_id uuid, _event text, _actor_role text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
declare
  t public.feedback_threads;
  _student_id uuid;
  _course_id uuid;
  _ref_id uuid;
  _student_link text;
  _teacher_link text;
  _parent_title text;
  _course_name text;
  _kind_label text;
  _actor_name text;
  _question_pos integer;
  _attempt_number integer;
  _question_label text;
  _title text;
  _body text;
  _count integer := 0;
begin
  select * into t from public.feedback_threads where id = _thread_id;
  if not found then
    return 0;
  end if;

  select full_name into _actor_name
  from public.profiles where id = auth.uid();

  if t.parent_kind = 'exam' then
    select user_id into _student_id from public.submissions where id = t.submission_id;
    select exam_id into _ref_id from public.questions where id = t.question_id;
    select course_id, e.title into _course_id, _parent_title
    from public.exams e where e.id = _ref_id;
    select position into _question_pos
    from public.questions where id = t.question_id;
    with ranked as (
      select s.id, row_number() over (
        partition by s.user_id, s.exam_id order by s.created_at
      ) as rn
      from public.submissions s
      where s.user_id = _student_id and s.exam_id = _ref_id
    )
    select rn::integer into _attempt_number from ranked where id = t.submission_id;
    _kind_label := 'Examen';
    _student_link := '/app/student/review/' || _ref_id::text;
    _teacher_link := '/app/teacher/monitor/' || _ref_id::text
      || '?student=' || _student_id::text;
  elsif t.parent_kind = 'workshop' then
    select user_id into _student_id from public.workshop_submissions where id = t.submission_id;
    select workshop_id into _ref_id from public.workshop_questions where id = t.question_id;
    select course_id, w.title into _course_id, _parent_title
    from public.workshops w where w.id = _ref_id;
    select position into _question_pos
    from public.workshop_questions where id = t.question_id;
    _kind_label := 'Taller';
    _student_link := '/app/student/workshop/' || _ref_id::text;

