CREATE OR REPLACE FUNCTION public.notify_send_push()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_url        text;
  v_secret     text;
  v_payload    jsonb;
  v_net_exists boolean;
BEGIN
  SELECT send_push_url, trigger_secret
    INTO v_url, v_secret
    FROM public.push_config
    WHERE id = 1;

  -- Sin URL configurada (tabla vacía o sin fila id=1) salimos limpio.
  -- La notificación queda persistida; el usuario la ve por realtime
  -- + polling — solo se pierde el Web Push real al device cerrado.
  IF v_url IS NULL OR v_url = '' THEN
    RETURN NEW;
  END IF;

  -- Si la extensión pg_net no está habilitada, el schema `net` no
  -- existe y `net.http_post` daría error en runtime — evitamos romper
  -- el INSERT padre.
  SELECT EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'net') INTO v_net_exists;
  IF NOT v_net_exists THEN
    RETURN NEW;
  END IF;

  v_payload := jsonb_build_object(
    'user_id', NEW.user_id,
    'title',   NEW.title,
    'body',    NEW.body,
    'link',    NEW.link,
    'kind',    NEW.kind,
    'notification_id', NEW.id
  );

  -- Header `X-Trigger-Secret` debe coincidir con el env
  -- `PUSH_TRIGGER_SECRET` del edge function `send-push`. Mismatch → 401.
  -- Authorization se omite a propósito: send-push tiene verify_jwt=false
  -- en config.toml y no consulta ese header.
  BEGIN
    PERFORM net.http_post(
      url := v_url,
      headers := jsonb_build_object(
        'Content-Type',     'application/json',
        'X-Trigger-Secret', COALESCE(v_secret, '')
      ),
      body := v_payload,
      timeout_milliseconds := 5000
    );
  EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE 'notify_send_push: pg_net call failed: %', SQLERRM;
  END;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.open_conversation(_other uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_me UUID := auth.uid();
  v_a UUID;
  v_b UUID;
  v_id UUID;
BEGIN
  IF v_me IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = '28000';
  END IF;
  IF NOT public.can_message(v_me, _other) THEN
    RAISE EXCEPTION 'No tienes permiso para mensajear a este usuario'
      USING ERRCODE = '42501';
  END IF;
  IF v_me < _other THEN
    v_a := v_me;  v_b := _other;
  ELSE
    v_a := _other; v_b := v_me;
  END IF;
  SELECT id INTO v_id FROM public.conversations
  WHERE user_a = v_a AND user_b = v_b;
  IF v_id IS NOT NULL THEN
    RETURN v_id;
  END IF;
  -- Idempotente ante carrera: si otra llamada concurrente ya insertó el par,
  -- ON CONFLICT no reinserta y re-seleccionamos el id ganador (sin 23505).
  INSERT INTO public.conversations (user_a, user_b)
  VALUES (v_a, v_b)
  ON CONFLICT (user_a, user_b) DO NOTHING
  RETURNING id INTO v_id;
  IF v_id IS NULL THEN
    SELECT id INTO v_id FROM public.conversations WHERE user_a = v_a AND user_b = v_b;
  END IF;
  RETURN v_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.purge_audit_logs()
 RETURNS TABLE(info_purged integer, warning_purged integer, error_purged integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_info INT := 0;
  v_warn INT := 0;
  v_err  INT := 0;
  v_cfg  RECORD;
BEGIN
  SELECT info_days, warning_days, error_days INTO v_cfg
    FROM public.audit_retention_settings LIMIT 1;

  IF v_cfg.info_days > 0 THEN
    WITH d AS (
      DELETE FROM public.audit_logs
      WHERE severity = 'info'
        AND created_at < NOW() - (v_cfg.info_days || ' days')::interval
      RETURNING 1
    )
    SELECT COUNT(*) INTO v_info FROM d;
  END IF;

  IF v_cfg.warning_days > 0 THEN
    WITH d AS (
      DELETE FROM public.audit_logs
      WHERE severity = 'warning'
        AND created_at < NOW() - (v_cfg.warning_days || ' days')::interval
      RETURNING 1
    )
    SELECT COUNT(*) INTO v_warn FROM d;
  END IF;

  IF v_cfg.error_days > 0 THEN
    WITH d AS (
      DELETE FROM public.audit_logs
      WHERE severity IN ('error', 'critical')
        AND created_at < NOW() - (v_cfg.error_days || ' days')::interval
      RETURNING 1
    )
    SELECT COUNT(*) INTO v_err FROM d;
  END IF;

  RETURN QUERY SELECT v_info, v_warn, v_err;
END
$function$

CREATE OR REPLACE FUNCTION public.purge_deleted_items(_ttl interval DEFAULT '30 days'::interval)
 RETURNS TABLE(table_name text, purged_count integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  tbl TEXT;
  tbls TEXT[] := ARRAY[
    -- Hijos primero — sus deleted_at > TTL se borran antes de que el
    -- tenant pase a hard-delete por FK cascade.
    'courses',
    'exams',
    'workshops',
    'projects',
    'attendance_sessions',
    'whiteboards',
    'generated_contents',
    'polls',
    -- Tenants al final.
    'tenants'
  ];
  cnt INT;
BEGIN
  FOREACH tbl IN ARRAY tbls
  LOOP
    IF to_regclass('public.' || tbl) IS NULL THEN
      CONTINUE;
    END IF;
    EXECUTE format(
      'DELETE FROM public.%I WHERE deleted_at IS NOT NULL AND deleted_at < now() - $1',
      tbl
    ) USING _ttl;
    GET DIAGNOSTICS cnt = ROW_COUNT;
    table_name := tbl;
    purged_count := cnt;
    RETURN NEXT;
  END LOOP;
  RETURN;
END;
$function$

CREATE OR REPLACE FUNCTION public.recompute_project_submission_grade(_submission_id uuid)
 RETURNS numeric
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_new_grade NUMERIC;
BEGIN
  IF NOT (
    public.has_role(auth.uid(), 'Docente') OR
    public.has_role(auth.uid(), 'Admin') OR
    public.is_super_admin()
  ) THEN
    RAISE EXCEPTION 'Permiso denegado: requiere rol Docente, Admin o SuperAdmin'
      USING ERRCODE = 'P0001';
  END IF;
  PERFORM public._recompute_project_submission_grade(_submission_id);
  SELECT submission_grade INTO v_new_grade
    FROM public.project_submissions WHERE id = _submission_id;
  RETURN v_new_grade;
END;
$function$

CREATE OR REPLACE FUNCTION public.regenerate_calendar_token()
 RETURNS TABLE(token text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
DECLARE
  _user uuid := auth.uid();
  _new_token text;
  i INT;
BEGIN
  IF _user IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;

  UPDATE public.student_calendar_tokens tbl
     SET revoked_at = now()
   WHERE tbl.user_id = _user AND tbl.revoked_at IS NULL;

  FOR i IN 1..10 LOOP
    _new_token := translate(
      encode(extensions.gen_random_bytes(24), 'base64'),
      '+/=', '-_'
    );
    _new_token := substring(_new_token, 1, 32);
    EXIT WHEN NOT EXISTS (
      SELECT 1 FROM public.student_calendar_tokens tbl
       WHERE tbl.token = _new_token
    );
  END LOOP;

  INSERT INTO public.student_calendar_tokens (user_id, token)
    VALUES (_user, _new_token);

  token := _new_token;
  created_at := now();
  RETURN NEXT;
END;
$function$

