CREATE OR REPLACE FUNCTION public.restore_course_cascade(_course_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller UUID := auth.uid();
  v_ts TIMESTAMPTZ;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = 'P0001';
  END IF;
  IF NOT public._can_manage_course(_course_id) THEN
    RAISE EXCEPTION 'No autorizado para restaurar este curso' USING ERRCODE = '42501';
  END IF;

  SELECT deleted_at INTO v_ts FROM public.courses WHERE id = _course_id;
  IF v_ts IS NULL THEN
    RAISE EXCEPTION 'El curso no está en la papelera' USING ERRCODE = 'P0001';
  END IF;

  UPDATE public.courses SET deleted_at = NULL, deleted_by = NULL WHERE id = _course_id;

  -- Restaurar SOLO los children con el mismo timestamp (los que cascadearon
  -- al borrar el curso). Borrados individuales previos quedan en papelera.
  UPDATE public.exams               SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
  UPDATE public.workshops           SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
  UPDATE public.projects            SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
  UPDATE public.attendance_sessions SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
  UPDATE public.whiteboards         SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
  UPDATE public.generated_contents  SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
  UPDATE public.polls               SET deleted_at = NULL, deleted_by = NULL WHERE course_id = _course_id AND deleted_at = v_ts;
END;
$function$

CREATE OR REPLACE FUNCTION public.restore_tenant(_tenant_id uuid)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_caller UUID := auth.uid();
  v_is_super BOOLEAN;
  v_ts TIMESTAMPTZ;
BEGIN
  IF v_caller IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = 'P0001';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.user_roles WHERE user_id = v_caller AND role = 'SuperAdmin'
  ) INTO v_is_super;

  IF NOT v_is_super THEN
    RAISE EXCEPTION 'Solo SuperAdmin puede restaurar instituciones' USING ERRCODE = 'P0001';
  END IF;

  SELECT deleted_at INTO v_ts FROM public.tenants WHERE id = _tenant_id;
  IF v_ts IS NULL THEN
    RAISE EXCEPTION 'La institución no está eliminada' USING ERRCODE = 'P0001';
  END IF;

  -- Restaurar el tenant.
  UPDATE public.tenants
     SET deleted_at = NULL, deleted_by = NULL
   WHERE id = _tenant_id;

  -- Restaurar SOLO los children con el mismo timestamp (= los que
  -- cascadearon en esta operación). Si un curso tenía deleted_at
  -- distinto (borrado manual previo), permanece en papelera.
  IF to_regclass('public.courses') IS NOT NULL THEN
    UPDATE public.courses
       SET deleted_at = NULL, deleted_by = NULL
     WHERE tenant_id = _tenant_id AND deleted_at = v_ts;
  END IF;

  IF to_regclass('public.exams') IS NOT NULL THEN
    UPDATE public.exams e
       SET deleted_at = NULL, deleted_by = NULL
      FROM public.courses c
     WHERE e.course_id = c.id
       AND c.tenant_id = _tenant_id
       AND e.deleted_at = v_ts;
  END IF;

  IF to_regclass('public.workshops') IS NOT NULL THEN
    UPDATE public.workshops w
       SET deleted_at = NULL, deleted_by = NULL
      FROM public.courses c
     WHERE w.course_id = c.id
       AND c.tenant_id = _tenant_id
       AND w.deleted_at = v_ts;
  END IF;

  IF to_regclass('public.projects') IS NOT NULL THEN
    UPDATE public.projects p
       SET deleted_at = NULL, deleted_by = NULL
      FROM public.courses c
     WHERE p.course_id = c.id
       AND c.tenant_id = _tenant_id
       AND p.deleted_at = v_ts;
  END IF;

  IF to_regclass('public.attendance_sessions') IS NOT NULL THEN
    UPDATE public.attendance_sessions a

CREATE OR REPLACE FUNCTION public.retry_failed_email_notifications()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'private'
AS $function$
DECLARE
  v_url           text;
  v_key           text;
  v_retried       int := 0;
  v_alerted       int := 0;
  v_net_exists    boolean;
  r               record;
  v_creator       uuid;
  v_failed_names  text;
  v_failed_count  int;
  v_subject       text;
BEGIN
  -- Settings y pg_net (mismo patrón que notify_send_email).
  SELECT value INTO v_url FROM private.app_settings WHERE key = 'send_email_url';
  SELECT value INTO v_key FROM private.app_settings WHERE key = 'service_role_key';
  SELECT EXISTS (SELECT 1 FROM pg_namespace WHERE nspname = 'net') INTO v_net_exists;

  IF v_url IS NULL OR NOT v_net_exists THEN
    RETURN jsonb_build_object('retried', 0, 'alerted', 0, 'reason', 'no_settings_or_no_pgnet');
  END IF;

  -- ─── A) REINTENTAR transitorios (con backoff exponencial) ─────────
  -- Patrones a reintentar: 4xx provider_error (típico 421/454),
  -- pg_net_call_failed, 'timeout' / 'temporary' / 'try again', y 503.
  -- NO reintenta: 5xx no-503, user_opted_out, no_settings, pg_net_missing,
  -- kind_not_critical (intencionales o de config — no se arreglan solos).
  FOR r IN
    SELECT id, user_id
    FROM public.notifications
    WHERE email_delivered_at IS NULL
      AND email_retry_count < 5
      AND created_at > now() - interval '24 hours'
      AND email_skipped_reason IS NOT NULL
      -- BACKOFF EXPONENCIAL: espaciado mínimo 5min × 2^retry_count desde el
      -- último intento. Evita que una ola de fallos (ej. 454 login throttle)
      -- se auto-sostenga martillando el SMTP cada tick del cron.
      AND (
        email_last_retry_at IS NULL
        OR email_last_retry_at < now() - (interval '5 minutes' * power(2, email_retry_count))
      )
      AND (
        email_skipped_reason ~* '^provider_error: 4[0-9]{2}'
        OR email_skipped_reason ~* '^pg_net_call_failed'
        OR email_skipped_reason ~* 'timeout'
        OR email_skipped_reason ~* 'temporary'
        OR email_skipped_reason ~* 'try again'
        OR email_skipped_reason ~* '^provider_error: 503'  -- 503 Ser

