      'user.email_change_reverted',

CREATE OR REPLACE FUNCTION public.revoke_certificate(_certificate_id uuid, _reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _cert RECORD;
BEGIN
  SELECT * INTO _cert FROM public.certificates WHERE id = _certificate_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Certificado no encontrado';
  END IF;
  IF _cert.revoked_at IS NOT NULL THEN
    RAISE EXCEPTION 'El certificado ya está revocado';
  END IF;
  -- Docente del curso, o Admin del tenant del curso, o SuperAdmin.
  IF NOT (
    public.is_admin_of_course_tenant(_cert.course_id) OR EXISTS (
      SELECT 1 FROM public.course_teachers
      WHERE course_id = _cert.course_id AND user_id = auth.uid()
    )
  ) THEN
    RAISE EXCEPTION 'No autorizado para revocar este certificado';
  END IF;
  UPDATE public.certificates
    SET revoked_at = now(),
        revoked_by = auth.uid(),
        revoke_reason = _reason
    WHERE id = _certificate_id;
  INSERT INTO public.notifications (user_id, title, body, kind, link)
  VALUES (
    _cert.user_id,
    'Tu certificado del curso "' || _cert.course_name || '" fue revocado',
    COALESCE('Motivo: ' || _reason, 'Sin motivo especificado.'),
    'system',
    '/app/student/certificates'
  );
END
$function$

CREATE OR REPLACE FUNCTION public.set_course_status(_course_id uuid, _status text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  DECLARE
    v_pending integer;
  BEGIN
    IF _status NOT IN ('borrador', 'en_curso', 'finalizado') THEN
      RAISE EXCEPTION 'Estado de curso inválido: %', _status;
    END IF;

    IF NOT (
      public.is_super_admin()
      OR (public.has_role(auth.uid(), 'Admin') AND public.course_in_my_tenant(_course_id))
      OR EXISTS (
        SELECT 1 FROM public.course_teachers ct
        WHERE ct.course_id = _course_id AND ct.user_id = auth.uid()
      )
    ) THEN
      RAISE EXCEPTION 'No autorizado para cambiar el estado de este curso';
    END IF;

    IF EXISTS (
      SELECT 1 FROM public.courses WHERE id = _course_id AND deleted_at IS NOT NULL
    ) THEN
      RAISE EXCEPTION 'No se puede cambiar el estado de un curso en la papelera';
    END IF;

    -- Finalizar EXIGE no tener pendientes de calificación.
    IF _status = 'finalizado' THEN
      v_pending := public.course_pending_grading_count(_course_id);
      IF v_pending > 0 THEN
        RAISE EXCEPTION 'No se puede finalizar el curso: hay % entrega(s) pendiente(s) de calificación. Califícalas (revisa el Diagnóstico del curso) antes de finalizar.', v_pending;
      END IF;
    END IF;

    UPDATE public.courses
      SET status = _status,
          finalized_at = CASE WHEN _status = 'finalizado' THEN now() ELSE NULL END,
          finalized_by = CASE WHEN _status = 'finalizado' THEN auth.uid() ELSE NULL END
      WHERE id = _course_id;
  END
  $function$

CREATE OR REPLACE FUNCTION public.set_error_events_status(_ids uuid[], _status text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_is_super BOOLEAN := public.is_super_admin();
  v_is_admin BOOLEAN := public.has_role(auth.uid(), 'Admin');
  v_my_tenant UUID := public.current_tenant_id();
  v_uid UUID := auth.uid();
  v_count INT;
BEGIN
  IF NOT v_is_super AND NOT v_is_admin THEN
    RAISE EXCEPTION 'No autorizado' USING ERRCODE = '42501';
  END IF;
  IF _status NOT IN ('nuevo', 'revisando', 'resuelto', 'ignorado') THEN
    RAISE EXCEPTION 'Estado inválido' USING ERRCODE = '22023';
  END IF;
  IF _ids IS NULL OR cardinality(_ids) = 0 THEN
    RETURN 0;
  END IF;

  WITH allowed AS (
    SELECT al.id
    FROM public.audit_logs al
    LEFT JOIN LATERAL (
      SELECT public._error_event_tenant(al.actor_id, al.course_id) AS tid
    ) der ON true
    WHERE al.id = ANY(_ids)
      AND al.severity = 'error'
      AND (v_is_super OR (v_is_admin AND der.tid = v_my_tenant))
  )
  INSERT INTO public.error_event_status (audit_log_id, status, reviewed_by, reviewed_at, updated_at)
  SELECT a.id, _status, v_uid, now(), now()
  FROM allowed a
  ON CONFLICT (audit_log_id) DO UPDATE
    SET status = EXCLUDED.status,
        reviewed_by = EXCLUDED.reviewed_by,
        reviewed_at = EXCLUDED.reviewed_at,
        updated_at = now();
  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$function$

CREATE OR REPLACE FUNCTION public.set_my_tenant_ai_mode(_mode text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_tenant uuid;
BEGIN
  IF _mode IS NULL OR _mode NOT IN ('shared', 'own') THEN
    RAISE EXCEPTION 'Modo de IA inválido: usa compartida (shared) o propia (own).'
      USING ERRCODE = '22023';
  END IF;
  IF NOT public.has_role(auth.uid(), 'Admin'::public.app_role) THEN
    RAISE EXCEPTION 'Solo un administrador de la institución puede cambiar el modo de IA.'
      USING ERRCODE = '42501';
  END IF;
  SELECT tenant_id INTO v_tenant FROM public.profiles WHERE id = auth.uid();
  IF v_tenant IS NULL THEN
    RAISE EXCEPTION 'No se pudo determinar tu institución.' USING ERRCODE = '42501';
  END IF;

