CREATE OR REPLACE FUNCTION public.tg_cap_due_date_to_course()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_max TIMESTAMPTZ;
BEGIN
  -- Externos: la fecha es un marcador del evento ya ocurrido — no se topa,
  -- igual que en el front.
  IF COALESCE(NEW.is_external, false) THEN RETURN NEW; END IF;
  IF NEW.course_id IS NULL OR NEW.due_date IS NULL THEN RETURN NEW; END IF;
  v_max := public._course_end_instant(NEW.course_id);
  IF v_max IS NOT NULL AND NEW.due_date > v_max THEN
    NEW.due_date := v_max;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tg_cap_end_time_to_course()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_max TIMESTAMPTZ;
BEGIN
  -- Externos: la fecha es un marcador del evento ya ocurrido (y end=start) — no
  -- se topa, igual que en el front.
  IF COALESCE(NEW.is_external, false) THEN RETURN NEW; END IF;
  IF NEW.course_id IS NULL OR NEW.end_time IS NULL THEN RETURN NEW; END IF;
  v_max := public._course_end_instant(NEW.course_id);
  IF v_max IS NOT NULL AND NEW.end_time > v_max THEN
    NEW.end_time := v_max;
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tg_cascade_close_on_course_finalized()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  BEGIN PERFORM public.close_exams_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_exams curso %: %', NEW.id, SQLERRM; END;
  BEGIN PERFORM public.close_workshops_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_workshops curso %: %', NEW.id, SQLERRM; END;
  BEGIN PERFORM public.close_projects_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_projects curso %: %', NEW.id, SQLERRM; END;
  BEGIN PERFORM public.close_whiteboards_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_whiteboards curso %: %', NEW.id, SQLERRM; END;
  BEGIN PERFORM public.close_polls_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_polls curso %: %', NEW.id, SQLERRM; END;
  BEGIN PERFORM public.close_forums_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_forums curso %: %', NEW.id, SQLERRM; END;
  BEGIN PERFORM public.close_checkin_for_course(NEW.id);
  EXCEPTION WHEN OTHERS THEN RAISE WARNING 'cascade close_checkin curso %: %', NEW.id, SQLERRM; END;
  RETURN NULL;  -- AFTER trigger: el retorno se ignora
END $function$

CREATE OR REPLACE FUNCTION public.tg_check_course_membership_tenant()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_course_tenant UUID;
  v_user_tenant   UUID;
BEGIN
  -- Tenant del curso. Si el curso no existe, el FK ya tira error —
  -- llegamos acá solo con un curso válido.
  SELECT tenant_id INTO v_course_tenant
    FROM public.courses WHERE id = NEW.course_id;

  -- Tenant del usuario.
  SELECT tenant_id INTO v_user_tenant
    FROM public.profiles WHERE id = NEW.user_id;

  IF v_course_tenant IS NULL THEN
    RAISE EXCEPTION 'El curso % no tiene tenant asignado', NEW.course_id
      USING ERRCODE = 'P0001';
  END IF;

  -- Si el profile aún no tiene tenant (ventana de invitación transitoria
  -- de Fase 1), también rechazamos. Forzar invariante: solo usuarios
  -- con tenant pueden ser miembros de cursos.
  IF v_user_tenant IS NULL THEN
    RAISE EXCEPTION 'El usuario % no tiene institución asignada', NEW.user_id
      USING ERRCODE = 'P0001';
  END IF;

  IF v_course_tenant <> v_user_tenant THEN
    RAISE EXCEPTION 'No se puede asignar un usuario de otra institución a este curso'
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tg_check_profile_tenant_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_enrollments INT;
  v_teaching    INT;
BEGIN
  -- Solo nos importa cuando tenant_id realmente cambia.
  IF OLD.tenant_id IS NOT DISTINCT FROM NEW.tenant_id THEN
    RETURN NEW;
  END IF;

  -- Caso "viejo = NULL" (ventana transitoria pre-Fase 6 — profile creado
  -- sin tenant + completado al aceptar invitación).
  IF OLD.tenant_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- ── NUEVO: el SuperAdmin opera cross-tenant. Cambiarle el tenant (o
  --    desligarlo a NULL) no le bloquea acceso a nada porque
  --    `is_super_admin()` bypassa la RLS de tablas con tenant scope.
  --    No exigimos limpiar matrículas/cursos del tenant viejo.
  IF EXISTS (
    SELECT 1 FROM public.user_roles
     WHERE user_id = NEW.id AND role = 'SuperAdmin'
  ) THEN
    RETURN NEW;
  END IF;

  -- Para no-SuperAdmin: si tiene cursos activos en el tenant viejo,
  -- rechazamos — sino perdería acceso a ellos por aislamiento de RLS.
  SELECT COUNT(*) INTO v_enrollments
    FROM public.course_enrollments e
    JOIN public.courses c ON c.id = e.course_id
   WHERE e.user_id = NEW.id AND c.tenant_id = OLD.tenant_id;

  SELECT COUNT(*) INTO v_teaching
    FROM public.course_teachers t
    JOIN public.courses c ON c.id = t.course_id
   WHERE t.user_id = NEW.id AND c.tenant_id = OLD.tenant_id;

  IF v_enrollments > 0 OR v_teaching > 0 THEN
    RAISE EXCEPTION 'No se puede cambiar la institución del usuario: tiene cursos activos en la institución actual (% como estudiante, % como docente)',
      v_enrollments, v_teaching
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tg_check_tenant_user_quota()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_tenant  UUID;
  v_max     INT;
  v_current INT;
  v_label   TEXT;
  v_column  TEXT;
BEGIN
  IF NEW.role::text = 'SuperAdmin' THEN
    RETURN NEW;
  END IF;

  SELECT tenant_id INTO v_tenant FROM public.profiles WHERE id = NEW.user_id;
  IF v_tenant IS NULL THEN
    RETURN NEW;
  END IF;

  CASE NEW.role::text
    WHEN 'Admin'      THEN v_column := 'max_admins';   v_label := 'administradores';
    WHEN 'Docente'    THEN v_column := 'max_teachers'; v_label := 'docentes';
    WHEN 'Estudiante' THEN v_column := 'max_students'; v_label := 'estudiantes';
    ELSE RETURN NEW;
  END CASE;

  EXECUTE format('SELECT %I FROM public.tenants WHERE id = $1', v_column)
    INTO v_max USING v_tenant;

  IF v_max IS NULL THEN
    RETURN NEW;
  END IF;

  -- Conteo centralizado (excluye inactivos). Si el usuario destino está
  -- inactivo, no se autocuenta — pero la reactivación NO pasa por aquí (no
  -- inserta user_roles), así que la edge admin-set-user-active re-chequea cuota.
  v_current := public.tenant_role_count(v_tenant, NEW.role);

  IF v_current >= v_max THEN
    RAISE EXCEPTION 'Cuota de % alcanzada (% / %). Aumenta el cupo desde el panel SuperAdmin, desactiva un usuario, o libera espacio quitando el rol a un usuario existente.',
      v_label, v_current, v_max
      USING ERRCODE = 'P0001';
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tg_conversations_tenant_check()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_ta UUID;
  v_tb UUID;
BEGIN
  -- El SuperAdmin opera cross-tenant (tenant_id NULL). can_message ya permite
  -- Admin↔SA; sin esta exención el trigger bloqueaba crear esa conversación.
  IF public.has_role(NEW.user_a, 'SuperAdmin'::app_role)
     OR public.has_role(NEW.user_b, 'SuperAdmin'::app_role) THEN
    RETURN NEW;
  END IF;
  SELECT tenant_id INTO v_ta FROM public.profiles WHERE id = NEW.user_a;
  SELECT tenant_id INTO v_tb FROM public.profiles WHERE id = NEW.user_b;
  IF v_ta IS NULL OR v_tb IS NULL THEN
    RAISE EXCEPTION 'Uno de los usuarios no tiene institución asignada'
      USING ERRCODE = 'P0001';
  END IF;
  IF v_ta <> v_tb THEN
    RAISE EXCEPTION 'No se puede iniciar una conversación entre usuarios de instituciones distintas'
      USING ERRCODE = 'P0001';
  END IF;
  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.tg_guard_profile_self_escalation()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_uid uuid := auth.uid();
  v_touch boolean;
  v_is_admin boolean;
BEGIN
  IF v_uid IS NULL THEN RETURN NEW; END IF;  -- service_role / sistema

  v_touch :=
       NEW.is_active      IS DISTINCT FROM OLD.is_active
    OR NEW.deactivated_at IS DISTINCT FROM OLD.deactivated_at
    OR NEW.deactivated_by IS DISTINCT FROM OLD.deactivated_by
    OR NEW.estado         IS DISTINCT FROM OLD.estado
    -- tenant_id: la PRIMERA asignación (OLD NULL) es onboarding legítimo; re-
    -- apuntar un tenant ya asignado es escalación cross-tenant.
    OR (NEW.tenant_id IS DISTINCT FROM OLD.tenant_id AND OLD.tenant_id IS NOT NULL);

  IF NOT v_touch THEN RETURN NEW; END IF;

  v_is_admin := public.is_super_admin() OR public.has_role(v_uid, 'Admin');
  IF v_is_admin THEN RETURN NEW; END IF;

  RAISE EXCEPTION 'No autorizado: solo un administrador puede cambiar el estado de activación, el estado académico o la institución de un usuario';
END
$function$

