      v_recipient,
      'Nuevo mensaje de ' || v_sender_name,
      v_body_preview,
      'info',
      '/app/messages',
      NEW.sender_id,
      NULL
    );
  ELSIF NEW.group_id IS NOT NULL THEN
    -- Grupo: notif a cada miembro != sender. group_chat_member_ids
    -- resuelve tanto chats de curso (dinámico) como ad-hoc (filas
    -- explícitas).
    SELECT title INTO v_group_title FROM public.group_chats WHERE id = NEW.group_id;
    INSERT INTO public.notifications (
      user_id, title, body, kind, link, related_user_id, source_role
    )
    SELECT
      m.user_id,
      CASE
        WHEN v_group_title IS NOT NULL THEN v_sender_name || ' · ' || v_group_title
        ELSE 'Nuevo mensaje de ' || v_sender_name
      END,
      v_body_preview,
      '

CREATE OR REPLACE FUNCTION public.tg_poll_courses_enforce_tenant()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_poll_tenant UUID;
  v_course_tenant UUID;
BEGIN
  -- Tenant de la encuesta = tenant de su curso ancla (polls.course_id).
  SELECT c.tenant_id INTO v_poll_tenant
    FROM public.polls p
    JOIN public.courses c ON c.id = p.course_id
   WHERE p.id = NEW.poll_id;
  SELECT tenant_id INTO v_course_tenant FROM public.courses WHERE id = NEW.course_id;

  IF v_poll_tenant IS DISTINCT FROM v_course_tenant THEN
    RAISE EXCEPTION 'No se puede vincular una encuesta a un curso de otra institución'
      USING ERRCODE = '42501';
  END IF;
  RETURN NEW;
END $function$

