CREATE OR REPLACE FUNCTION public.tg_support_tickets_guard_admin_columns()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  -- El SuperAdmin gestiona todo el ciclo (asignación, notas de resolución).
  IF public.is_super_admin() THEN
    RETURN NEW;
  END IF;
  -- El resto de callers que la RLS deja pasar es el Admin DUEÑO del ticket:
  -- puede tocar status/priority/subject/body, pero NO las columnas que son
  -- prerrogativa del SuperAdmin ni las de identidad/soft-delete. Congelamos a
  -- su valor previo (en vez de RAISE) para no romper un UPDATE legítimo que
  -- reenvíe la fila completa desde el cliente.
  NEW.resolution_notes := OLD.resolution_notes;
  NEW.assigned_to      := OLD.assigned_to;
  NEW.tenant_id        := OLD.tenant_id;
  NEW.created_by       := OLD.created_by;
  NEW.deleted_at       := OLD.deleted_at;
  NEW.deleted_by       := OLD.deleted_by;
  RETURN NEW;
END
$function$

CREATE OR REPLACE FUNCTION public.tg_workshop_answer_graded_recompute()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _sub_id   UUID := NEW.submission_id;
  _ws_id    UUID;
  _max      NUMERIC;
  _total    NUMERIC;
  _earned   NUMERIC;
  _pending  INT;
  _final    NUMERIC;
BEGIN
  SELECT ws.workshop_id INTO _ws_id
    FROM public.workshop_submissions ws WHERE ws.id = _sub_id;
  IF _ws_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- ¿Quedan respuestas que la IA DEBE calificar todavía sin nota? Las
  -- preguntas cerradas (scoring local) NO cuentan — si no, bloquearían
  -- el cierre indefinidamente.
  SELECT count(*) INTO _pending
    FROM public.workshop_submission_answers a
    JOIN public.workshop_questions q ON q.id = a.question_id
   WHERE a.submission_id = _sub_id
     AND q.type NOT IN ('cerrada', 'cerrada_multi')
     AND a.ai_grade IS NULL;
  IF _pending > 0 THEN
    RETURN NEW; -- aún faltan preguntas abiertas/código por calificar
  END IF;

  SELECT w.max_score INTO _max FROM public.workshops w WHERE w.id = _ws_id;
  SELECT COALESCE(SUM(points), 0) INTO _total
    FROM public.workshop_questions WHERE workshop_id = _ws_id;
  SELECT COALESCE(SUM(ai_grade), 0) INTO _earned
    FROM public.workshop_submission_answers WHERE submission_id = _sub_id;

  IF _total <= 0 THEN
    _final := 0;
  ELSE
    _final := round((_earned / _total) * COALESCE(_max, 100), 2);
  END IF;

  -- Refrescamos ai_grade y la nota final. final_grade se respeta SOLO si el
  -- docente lo sobreescribió manualmente (≠ del ai_grade previo); si era el
  -- auto previo (o NULL), se actualiza al nuevo valor — así regenerar también
  -- corrige la nota. No tocamos entregas marcadas 'sospechoso' (revisión de
  -- fraude manual) más allá de refrescar su grade.
  UPDATE public.workshop_submissions
     SET ai_grade    = _final,
         final_grade = CASE
                         WHEN final_grade IS NULL THEN _final
                         WHEN final_grade = ai_grade THEN _final
                         ELSE final_grade
                       END,
         status      = CASE WHEN status IN ('entregado', 'ai_revisado') THEN 'calificad

CREATE OR REPLACE FUNCTION public.toggle_forum_closed(_forum_id uuid, _close boolean)
 RETURNS timestamp with time zone
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _course_id UUID;
  _new_value TIMESTAMPTZ;
BEGIN
  SELECT course_id INTO _course_id FROM public.forums WHERE id = _forum_id;
  IF _course_id IS NULL THEN
    RAISE EXCEPTION 'Foro no encontrado';
  END IF;

  IF NOT (
    public.has_role(auth.uid(), 'Admin')
    OR EXISTS (
      SELECT 1 FROM public.course_teachers
      WHERE course_id = _course_id AND user_id = auth.uid()
    )
  ) THEN
    RAISE EXCEPTION 'Solo el docente del curso o admin pueden cerrar o reabrir un foro';
  END IF;

  _new_value := CASE WHEN _close THEN now() ELSE NULL END;
  UPDATE public.forums SET manually_closed_at = _new_value WHERE id = _forum_id;
  RETURN _new_value;
END
$function$

CREATE OR REPLACE FUNCTION public.toggle_forum_upvote(_target_type text, _target_id uuid)
 RETURNS TABLE(upvoted boolean, total integer)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _exists BOOLEAN;
  _total INT;
BEGIN
  IF _target_type NOT IN ('thread', 'reply') THEN
    RAISE EXCEPTION 'target_type debe ser "thread" o "reply"';
  END IF;
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'No autenticado';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.forum_upvotes
    WHERE user_id = auth.uid()
      AND target_type = _target_type
      AND target_id = _target_id
  ) INTO _exists;

  IF _exists THEN
    DELETE FROM public.forum_upvotes
      WHERE user_id = auth.uid()
        AND target_type = _target_type
        AND target_id = _target_id;
  ELSE
    INSERT INTO public.forum_upvotes (user_id, target_type, target_id)
      VALUES (auth.uid(), _target_type, _target_id);
  END IF;

  IF _target_type = 'thread' THEN
    SELECT upvotes INTO _total FROM public.forum_threads WHERE id = _target_id;
  ELSE
    SELECT upvotes INTO _total FROM public.forum_replies WHERE id = _target_id;
  END IF;

  RETURN QUERY SELECT (NOT _exists), COALESCE(_total, 0);
END
$function$

CREATE OR REPLACE FUNCTION public.trigger_retry_failed_ai_gradings()
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_url    text := current_setting('app.settings.retry_grading_url', true);
  v_secret text := current_setting('app.settings.retry_grading_secret', true);
BEGIN
  IF v_url IS NULL OR v_url = '' OR v_secret IS NULL OR v_secret = '' THEN
    RAISE NOTICE 'retry_grading_url/secret no configurados — skip';
    RETURN;
  END IF;

  PERFORM net.http_post(
    url := v_url,
    headers := jsonb_build_object(
      'Content-Type',     'application/json',
      'X-Trigger-Secret', v_secret
    ),
    body := '{}'::jsonb,
    timeout_milliseconds := 60000
  );
END
$function$

CREATE OR REPLACE FUNCTION public.update_session_whiteboard_scene(_session_id uuid, _scene jsonb)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_course_id UUID;
  v_shared BOOLEAN;
  v_deleted_at TIMESTAMPTZ;
  v_is_teacher BOOLEAN;
  v_is_enrolled BOOLEAN;
BEGIN
  -- Cota de tamaño (anti-abuso): 5 MB es holgado para una escena legítima.
  IF octet_length(_scene::text) > 5 * 1024 * 1024 THEN
    RAISE EXCEPTION 'La escena de la pizarra es demasiado grande (máximo 5 MB)'
      USING ERRCODE = 'P0001';
  END IF;
  -- Cargar curso + estado de share + papelera. NULL = sesión no existe.
  SELECT course_id, COALESCE(whiteboard_shared, false), deleted_at
  INTO v_course_id, v_shared, v_deleted_at
  FROM public.attendance_sessions
  WHERE id = _session_id;
  IF v_course_id IS NULL THEN
    RAISE EXCEPTION 'Sesión no encontrada' USING ERRCODE = 'P0001';
  END IF;
  -- Papelera: una sesión borrada no se edita por nadie.
  IF v_deleted_at IS NOT NULL THEN
    RAISE EXCEPTION 'La sesión está en la papelera' USING ERRCODE = 'P0001';
  END IF;
  -- Docente / Admin / SuperAdmin: bypass directo.
  v_is_teacher := EXISTS (
    SELECT 1 FROM public.course_teachers
    WHERE course_id = v_course_id AND user_id = auth.uid()
  ) OR public.has_role(auth.uid(), 'Admin'::public.app_role)
    OR public.is_super_admin();
  IF NOT v_is_teacher THEN
    -- Alumno: solo si shared=true Y matriculado en el curso.
    IF NOT v_shared THEN
      RAISE EXCEPTION 'La pizarra no está compartida' USING ERRCODE = 'P0001';
    END IF;
    v_is_enrolled := EXISTS (
      SELECT 1 FROM public.course_enrollments
      WHERE course_id = v_course_id AND user_id = auth.uid()
    );
    IF NOT v_is_enrolled THEN
      RAISE EXCEPTION 'No estás matriculado en este curso' USING ERRCODE = 'P0001';
    END IF;
  END IF;
  -- Pasada la validación, escribimos. NO tocamos updated_at — el trigger
  -- existente lo maneja si está configurado para esa tabla.
  UPDATE public.attendance_sessions
  SET whiteboard_scene = _scene
  WHERE id = _session_id;
END;
$function$

CREATE OR REPLACE FUNCTION public.vote_poll_option(_option_id uuid)
 RETURNS TABLE(response_id uuid, poll_id uuid, option_id uuid)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_poll public.polls;
  v_option public.poll_options;
  v_uid UUID := auth.uid();
  v_enrolled BOOLEAN;
  v_response_id UUID;
BEGIN
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'No autenticado' USING ERRCODE = '42501';
  END IF;
  SELECT * INTO v_option FROM public.poll_options WHERE id = _option_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Opción inexistente' USING ERRCODE = '22023';
  END IF;
  SELECT * INTO v_poll FROM public.polls WHERE id = v_option.poll_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Encuesta inexistente' USING ERRCODE = '22023';
  END IF;
  IF NOT v_poll.is_published THEN
    RAISE EXCEPTION 'Esta encuesta todavía es un borrador' USING ERRCODE = 'P0001';
  END IF;
  IF NOT public.poll_is_open(v_poll) THEN
    RAISE EXCEPTION 'La encuesta está cerrada' USING ERRCODE = 'P0001';
  END IF;
  SELECT EXISTS (
    SELECT 1
      FROM public.poll_courses pc
      JOIN public.course_enrollments ce ON ce.course_id = pc.course_id
     WHERE pc.poll_id = v_poll.id AND ce.user_id = v_uid
  ) INTO v_enrolled;
  IF NOT v_enrolled THEN
    RAISE EXCEPTION 'No estás matriculado en ningún curso de esta encuesta'
      USING ERRCODE = '42501';
  END IF;
  IF v_poll.poll_type = 'slot' THEN
    IF v_option.max_responses IS NULL THEN
      RAISE EXCEPTION 'La opción no tiene cupo configurado' USING ERRCODE = '22023';
    END IF;
    PERFORM 1 FROM public.poll_options
      WHERE id = _option_id AND responses_count < max_responses
      FOR UPDATE;
    IF NOT FOUND THEN
      RAISE EXCEPTION 'Cupo agotado para esta opción' USING ERRCODE = 'P0001';
    END IF;
  END IF;
  INSERT INTO public.poll_responses (poll_id, option_id, user_id)
       VALUES (v_poll.id, _option_id, v_uid)
    RETURNING id INTO v_response_id;
  RETURN QUERY SELECT v_response_id, v_poll.id, _option_id;
END;
$function$
